const pending = new Map();
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

async function getUser(id) {
  const cached = cache.get(id);
  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    return cached.data;
  }

  // Deduplicate concurrent requests for same id
  if (pending.has(id)) {
    return pending.get(id);
  }

  const promise = db.query('SELECT * FROM users WHERE id = $1', [id])
    .then(user => {
      cache.set(id, { data: user, timestamp: Date.now() });
      pending.delete(id);
      return user;
    })
    .catch(err => {
      pending.delete(id);
      throw err;
    });

  pending.set(id, promise);
  return promise;
}
```

This fixes all three: parameterized query, TTL-based expiration, and request coalescing for concurrent access.
